import type { PublicCard } from '../../../types';

export const gcseFormulasCardsPart2: PublicCard[] = [
  // ── STATISTICS FORMULAS (cards 151–200) ───────────────────────────────────
  { id: 'dc-gcse-formulas-0151', deck_id: 'deck-gcse-formulas', front: 'Formula: Mean from a list', back: 'Mean = Sum of all values / Number of values\n  x̄ = Σx / n\n\nGCSE Tip: Pronounced "x-bar". The mean is affected by outliers (extreme values). Use the median instead of the mean when data is skewed or has outliers.', sort_order: 151 },
  { id: 'dc-gcse-formulas-0152', deck_id: 'deck-gcse-formulas', front: 'Formula: Mean from a frequency table', back: 'Mean = Σ(f × x) / Σf\n\n  f = frequency of each value\n  x = data value\n  Σf = total frequency (= n)\n\nAdd a column for fx, sum it, then divide by total frequency.\n\nGCSE Tip: Never just average the x-values — you MUST weight each value by its frequency. Always show the fx column.', sort_order: 152 },
  { id: 'dc-gcse-formulas-0153', deck_id: 'deck-gcse-formulas', front: 'Formula: Estimated mean from a grouped frequency table', back: 'Estimated mean ≈ Σ(midpoint × f) / Σf\n\nUse the MIDPOINT of each class interval as x.\n  Midpoint = (lower boundary + upper boundary) / 2\n\nGCSE Tip: This is only an ESTIMATE because all values within a class are assumed to be at the midpoint. State "estimated mean" in your answer.', sort_order: 153 },
  { id: 'dc-gcse-formulas-0154', deck_id: 'deck-gcse-formulas', front: 'Formula: Median position in ordered data', back: 'For n data values in order:\n  Median position = (n + 1)/2 th value\n\nIf n is odd: middle single value.\nIf n is even: average of the two middle values.\n\nCumulative frequency: median at n/2 th value (reading from the ogive).\n\nGCSE Tip: Always SORT the data first. The median is the middle value — not the arithmetic mean.', sort_order: 154 },
  { id: 'dc-gcse-formulas-0155', deck_id: 'deck-gcse-formulas', front: 'Formula: Range and interquartile range (IQR)', back: 'Range = maximum − minimum\n\nIQR = Q3 − Q1\n  Q1 = lower quartile (median of lower half)\n  Q3 = upper quartile (median of upper half)\n\nGCSE Tip: Range is affected by outliers. IQR measures the spread of the middle 50% and is resistant to outliers — better for comparing spread.', sort_order: 155 },
  { id: 'dc-gcse-formulas-0156', deck_id: 'deck-gcse-formulas', front: 'Formula: Quartiles from a list', back: 'For n data values in ascending order:\n  Q1 (lower quartile): median of the lower half (below overall median)\n  Q3 (upper quartile): median of the upper half (above overall median)\n\nFor n even: split into two equal halves (exclude the median if n is odd).\n\nGCSE Tip: Different exam boards use slightly different methods for quartiles. Check your specification, but the principle is the same: Q1 is at the 25% mark, Q3 at the 75% mark.', sort_order: 156 },
  { id: 'dc-gcse-formulas-0157', deck_id: 'deck-gcse-formulas', front: 'Formula: Cumulative frequency', back: 'Cumulative frequency = running total of frequencies up to (and including) each class.\n\nPlot cumulative frequency against UPPER CLASS BOUNDARY to form an ogive (S-curve).\n\nFrom the ogive:\n  Median: at cumulative freq = n/2\n  LQ: at cumulative freq = n/4\n  UQ: at cumulative freq = 3n/4\n\nGCSE Tip: The curve is S-shaped and should never decrease. Plot at upper boundaries, not midpoints.', sort_order: 157 },
  { id: 'dc-gcse-formulas-0158', deck_id: 'deck-gcse-formulas', front: 'Formula: Frequency density (histograms)', back: 'Frequency density = frequency / class width\n  →  Frequency = frequency density × class width  (= area of bar)\n\nHistograms: y-axis is FREQUENCY DENSITY (not frequency).\nArea of bar = frequency (number of data points in that class).\n\nGCSE Tip: For equal class widths, frequency density is proportional to frequency (heights directly comparable). For unequal class widths, always use area = frequency.', sort_order: 158 },
  { id: 'dc-gcse-formulas-0159', deck_id: 'deck-gcse-formulas', front: 'Formula: Moving average (time series)', back: 'n-point moving average: mean of n consecutive data points.\n\nFor a 4-point moving average:\n  MA₁ = (x₁ + x₂ + x₃ + x₄) / 4\n  MA₂ = (x₂ + x₃ + x₄ + x₅) / 4\n  …\n\nPlot each average at the centre of its group.\n\nGCSE Tip: Moving averages smooth out seasonal variation to reveal the underlying trend. A 4-point average is used for quarterly data (removes the 4-season cycle).', sort_order: 159 },
  { id: 'dc-gcse-formulas-0160', deck_id: 'deck-gcse-formulas', front: 'Formula: Pie chart angles', back: 'Angle for each sector = (frequency / total) × 360°\n\nExample: 40 students; 15 prefer science.\n  Angle = (15/40) × 360° = 135°\n\nTo find frequency from angle:\n  frequency = (angle / 360°) × total\n\nGCSE Tip: All sectors must sum to 360°. Draw sectors accurately with a protractor; label each sector with the category and value/percentage.', sort_order: 160 },
  { id: 'dc-gcse-formulas-0161', deck_id: 'deck-gcse-formulas', front: 'Formula: Expected frequency', back: 'Expected frequency = probability × number of trials\n\nExample: Fair die, rolled 120 times.\n  Expected frequency of 6 = (1/6) × 120 = 20\n\nCompare with observed frequency to test for bias or fairness.\n\nGCSE Tip: Expected frequency can be a decimal (it is a long-run average). Use observed vs expected to comment on whether an experiment is fair.', sort_order: 161 },
  { id: 'dc-gcse-formulas-0162', deck_id: 'deck-gcse-formulas', front: 'Formula: Relative frequency (experimental probability)', back: 'Relative frequency = number of times event occurred / total number of trials\n\nAs trials → ∞, relative frequency → theoretical probability\n\nGCSE Tip: Relative frequency is experimental probability. More trials → more reliable estimate. Plot "relative frequency vs number of trials" — the graph should converge (stabilise) towards the theoretical value.', sort_order: 162 },
  { id: 'dc-gcse-formulas-0163', deck_id: 'deck-gcse-formulas', front: 'Formula: Stratified sampling', back: 'Number from stratum = (stratum size / population size) × sample size\n\nExample: School: 300 Year 10, 200 Year 11, 500 total. Sample 50.\n  Year 10: (300/500) × 50 = 30\n  Year 11: (200/500) × 50 = 20\n  Check: 30 + 20 = 50 ✓\n\nGCSE Tip: Stratified sampling ensures each subgroup is proportionally represented. Always verify the parts sum to the total sample size.', sort_order: 163 },
  { id: 'dc-gcse-formulas-0164', deck_id: 'deck-gcse-formulas', front: 'Formula: Two-way tables — finding missing values', back: 'Two-way table structure:\n  Each cell = frequency for that combination.\n  Row total = sum of all values in that row.\n  Column total = sum of all values in that column.\n  Grand total = sum of all row totals = sum of all column totals.\n\nTo find a missing value: use row or column total − known values.\n\nGCSE Tip: Always fill in the row and column totals first. Then use subtraction to find missing cells.', sort_order: 164 },
  { id: 'dc-gcse-formulas-0165', deck_id: 'deck-gcse-formulas', front: 'Formula: Box plot (five-number summary)', back: 'Five-number summary: Minimum, Q1, Median (Q2), Q3, Maximum.\n\nBox plot construction:\n  Box: from Q1 to Q3 (width = IQR)\n  Line inside box: median\n  Whiskers: minimum to Q1, and Q3 to maximum\n  Scale: drawn accurately on a number line\n\nGCSE Tip: Outliers (if identified) are shown as crosses beyond the whiskers. The whiskers stop at the last non-outlier value.', sort_order: 165 },
  { id: 'dc-gcse-formulas-0166', deck_id: 'deck-gcse-formulas', front: 'Formula: Comparing distributions (box plots)', back: 'Compare location (average): compare medians.\nCompare spread: compare IQRs (or ranges).\n\nFull comparison statement:\n  "Group A has a [higher/lower] median than Group B, indicating [higher/lower] typical values.\n   Group A has a [larger/smaller] IQR, suggesting [more/less] consistent results."\n\nGCSE Tip: Two statements are needed for full marks — one about average, one about spread. Always reference specific values.', sort_order: 166 },
  { id: 'dc-gcse-formulas-0167', deck_id: 'deck-gcse-formulas', front: 'Formula: Standard deviation (concept, not GCSE formula)', back: 'Standard deviation measures how spread out data is around the mean.\n  Low SD → data clustered near the mean.\n  High SD → data spread far from the mean.\n\nAt GCSE, SD is typically calculated using a calculator (statistics mode).\n\nGCSE Tip: GCSE exams may ask you to interpret SD or compare SDs between two datasets. They do NOT require you to calculate SD by hand — use a calculator.', sort_order: 167 },
  { id: 'dc-gcse-formulas-0168', deck_id: 'deck-gcse-formulas', front: 'Formula: Frequency polygon', back: 'Plot (midpoint of class, frequency) for each class.\nJoin consecutive points with straight lines.\n\nFor comparison: draw two frequency polygons on the same axes.\n\nGCSE Tip: Use midpoints, NOT class boundaries. Frequency polygons allow comparison of two or more datasets on the same graph more clearly than histograms.', sort_order: 168 },
  { id: 'dc-gcse-formulas-0169', deck_id: 'deck-gcse-formulas', front: 'Formula: Skewness of a distribution', back: 'Positive skew: long tail to the RIGHT.\n  Mean > Median > Mode\n\nNegative skew: long tail to the LEFT.\n  Mean < Median < Mode\n\nSymmetric: Mean = Median = Mode\n\nGCSE Tip: From a box plot: if the median is closer to Q1 → positively skewed; closer to Q3 → negatively skewed. From a histogram: the tail indicates the direction of skew.', sort_order: 169 },
  { id: 'dc-gcse-formulas-0170', deck_id: 'deck-gcse-formulas', front: 'Formula: Estimating values from a histogram', back: 'Frequency = frequency density × class width  (= area of bar)\n\nTo estimate number of values above/below a specific value within a class:\n  Assume uniform distribution within the class.\n  Fraction of class × frequency of class.\n\nGCSE Tip: Always calculate the area (frequency) from the histogram — do NOT read heights as frequencies when class widths differ.', sort_order: 170 },
  { id: 'dc-gcse-formulas-0171', deck_id: 'deck-gcse-formulas', front: 'Formula: Scatter diagram — line of best fit', back: 'A line of best fit:\n  • Is a straight line.\n  • Has roughly equal numbers of points above and below.\n  • Ideally passes through (or near) the mean point (x̄, ȳ).\n  • Extends across the full data range.\n\nUse for interpolation (within data range — reliable) and extrapolation (beyond range — less reliable).\n\nGCSE Tip: Draw with a ruler. Do NOT connect dot-to-dot. One clear line through the spread of data.', sort_order: 171 },
  { id: 'dc-gcse-formulas-0172', deck_id: 'deck-gcse-formulas', front: 'Formula: Correlation descriptions', back: 'Positive correlation: as x increases, y increases.\nNegative correlation: as x increases, y decreases.\nNo correlation: no clear pattern.\n\nStrength:\n  Strong: points close to the line of best fit.\n  Weak: points spread widely.\n\nGCSE Tip: Always state BOTH direction (positive/negative) and strength (strong/weak). Correlation does NOT mean causation.', sort_order: 172 },
  { id: 'dc-gcse-formulas-0173', deck_id: 'deck-gcse-formulas', front: 'Formula: Finding mean and median from a stem-and-leaf diagram', back: 'Read all values (stem × 10 + leaf), ordered from smallest to largest.\n\nMean: sum all values, divide by count.\nMedian: locate the ((n+1)/2)th position in the ordered list.\nMode: leaf that appears most in any one stem.\n\nGCSE Tip: A back-to-back stem-and-leaf allows direct comparison of two datasets. Count all leaves for n. Be careful reading the LEFT-side leaves (they go right to left).', sort_order: 173 },
  { id: 'dc-gcse-formulas-0174', deck_id: 'deck-gcse-formulas', front: 'Formula: Outlier detection', back: 'Formal rule:\n  Outlier if value < Q1 − 1.5 × IQR\n  or value > Q3 + 1.5 × IQR\n\nGCSE Tip: At GCSE, outliers are often identified informally ("a value much larger/smaller than the rest"). The formal rule may be used at Higher. Outliers inflate the range and the mean — the median and IQR are more robust measures when outliers are present.', sort_order: 174 },
  { id: 'dc-gcse-formulas-0175', deck_id: 'deck-gcse-formulas', front: 'Formula: Class midpoints for grouped data', back: 'Midpoint of a class = (lower class boundary + upper class boundary) / 2\n\nExamples:\n  Class 10–20: midpoint = 15\n  Class 20–30: midpoint = 25\n  Class 0–5: midpoint = 2.5\n\nUsed for: estimated mean, frequency polygon, and frequency density calculations.\n\nGCSE Tip: For class "10 < x ≤ 20", boundaries are 10 and 20, midpoint = 15. Watch for continuous (≤) vs discrete interval boundaries.', sort_order: 175 },
  { id: 'dc-gcse-formulas-0176', deck_id: 'deck-gcse-formulas', front: 'Formula: Interpreting time series graphs', back: 'Time series: line graph where x-axis = time.\n\nGradient of graph = rate of change.\nTrend: overall direction (upward, downward, or stable).\nSeasonal variation: regular fluctuations that repeat each cycle.\nMoving average: removes seasonal variation to show the trend.\n\nGCSE Tip: "Describe the trend" → state the general direction AND any notable features (e.g. "generally increasing with seasonal peaks each summer").', sort_order: 176 },
  { id: 'dc-gcse-formulas-0177', deck_id: 'deck-gcse-formulas', front: 'Formula: Questionnaire design criteria', back: 'A good questionnaire question:\n  ✓ Clear and unambiguous\n  ✓ Not leading or biased\n  ✓ Includes all possible response options (exhaustive)\n  ✓ Response options do NOT overlap\n  ✓ Has a "no opinion" or "other" option where appropriate\n\nExample of a bad response: "How often do you exercise? Often | Sometimes | Rarely" (vague, overlapping)\n\nGCSE Tip: GCSE "criticise" questions — always look for leading wording, overlapping class intervals, and missing response options.', sort_order: 177 },
  { id: 'dc-gcse-formulas-0178', deck_id: 'deck-gcse-formulas', front: 'Formula: Median and quartiles from a cumulative frequency graph', back: 'From the cumulative frequency curve (n data points):\n  Median: read x-value at cumulative freq = n/2\n  Lower quartile (Q1): at cumulative freq = n/4\n  Upper quartile (Q3): at cumulative freq = 3n/4\n  IQR = Q3 − Q1\n\nMethod: draw horizontal line to curve → vertical line down to x-axis → read value.\n\nGCSE Tip: Use a pencil and ruler to draw the horizontal and vertical lines. State the values read off clearly.', sort_order: 178 },
  { id: 'dc-gcse-formulas-0179', deck_id: 'deck-gcse-formulas', front: 'Formula: Sampling methods summary', back: 'Random: each member has equal chance. Names in a hat, random number generator.\nSystematic: every nth member from a list. (k = population/sample size)\nStratified: proportion from each subgroup. (subgroup/total × sample size)\nConvenience: easiest to reach — likely biased.\nCluster: random selection of groups.\n\nGCSE Tip: "Describe how to take a stratified sample" → state the formula and how many from each stratum. Explain why it is more representative than simple random sampling.', sort_order: 179 },
  { id: 'dc-gcse-formulas-0180', deck_id: 'deck-gcse-formulas', front: 'Formula: Primary vs secondary data — advantages', back: 'Primary data (collected yourself):\n  ✓ Specific to your question\n  ✓ Up to date\n  ✗ Time-consuming and expensive\n\nSecondary data (collected by others):\n  ✓ Quick and cheap\n  ✓ Large datasets available\n  ✗ May not match your needs; may be biased or outdated\n\nGCSE Tip: GCSE questions often ask you to give ONE advantage or disadvantage of each type. Use the above as a reference.', sort_order: 180 },

  // ── PROBABILITY FORMULAS (cards 181–220) ──────────────────────────────────
  { id: 'dc-gcse-formulas-0181', deck_id: 'deck-gcse-formulas', front: 'Formula: Basic probability', back: 'P(A) = number of favourable outcomes / total number of equally likely outcomes\n  = n(A) / n(S)\n\n0 ≤ P(A) ≤ 1\nP(impossible) = 0\nP(certain) = 1\n\nGCSE Tip: "Probability" is always between 0 and 1. Express as a fraction, decimal, or percentage. "Equally likely" is a key assumption.', sort_order: 181 },
  { id: 'dc-gcse-formulas-0182', deck_id: 'deck-gcse-formulas', front: 'Formula: Complement rule', back: 'P(not A) = 1 − P(A)\n\nP(A\') = 1 − P(A)  [A\' means "not A"]\n\nApplication:\n  P(at least one) = 1 − P(none)\n\nGCSE Tip: Use the complement whenever it is easier to calculate "not happening" than "happening". "At least one" questions are almost always easier with 1 − P(none).', sort_order: 182 },
  { id: 'dc-gcse-formulas-0183', deck_id: 'deck-gcse-formulas', front: 'Formula: Mutually exclusive events (addition rule)', back: 'Mutually exclusive: P(A and B) = 0 (cannot both happen).\n\n  P(A or B) = P(A) + P(B)\n\nGeneral (non-mutually exclusive):\n  P(A or B) = P(A) + P(B) − P(A and B)\n\nGCSE Tip: "Mutually exclusive" means the events cannot occur simultaneously. For multiple mutually exclusive outcomes: P(A) + P(B) + P(C) + … = total probability (can equal 1 for exhaustive events).', sort_order: 183 },
  { id: 'dc-gcse-formulas-0184', deck_id: 'deck-gcse-formulas', front: 'Formula: Independent events (multiplication rule)', back: 'Independent events: outcome of one does NOT affect the other.\n\n  P(A and B) = P(A) × P(B)\n\nFor three independent events:\n  P(A and B and C) = P(A) × P(B) × P(C)\n\nGCSE Tip: Sampling WITH replacement → events are independent. Sampling WITHOUT replacement → events are dependent (use tree diagram and update probabilities).', sort_order: 184 },
  { id: 'dc-gcse-formulas-0185', deck_id: 'deck-gcse-formulas', front: 'Formula: Conditional probability', back: 'P(A|B) = probability of A given that B has occurred.\n\n  P(A|B) = P(A ∩ B) / P(B)\n\nFrom a two-way table: restrict to the B row/column.\n\nGCSE Tip: "Given that…" → conditional probability. The denominator is the total for the GIVEN condition (not the overall total). This is a frequently tested Higher topic.', sort_order: 185 },
  { id: 'dc-gcse-formulas-0186', deck_id: 'deck-gcse-formulas', front: 'Formula: P(A ∪ B) — general addition rule', back: 'P(A ∪ B) = P(A) + P(B) − P(A ∩ B)\n\nThis avoids double-counting the overlap.\n\nRearranged: P(A ∩ B) = P(A) + P(B) − P(A ∪ B)\n\nGCSE Tip: If you know three of the four values (P(A), P(B), P(A∩B), P(A∪B)), you can find the fourth. Venn diagrams help visualise this.', sort_order: 186 },
  { id: 'dc-gcse-formulas-0187', deck_id: 'deck-gcse-formulas', front: 'Formula: Probability tree diagram', back: 'Branches: represent possible outcomes at each stage.\nProbabilities on branches at each node sum to 1.\n\nOperations:\n  Multiply ALONG branches → probability of combined outcomes.\n  Add ACROSS compatible outcomes → total probability.\n\nExample: P(RR) = P(R) × P(R|first R)\n  P(one red) = P(RB) + P(BR)\n\nGCSE Tip: Always label branches AND outcomes at the end of each complete path.', sort_order: 187 },
  { id: 'dc-gcse-formulas-0188', deck_id: 'deck-gcse-formulas', front: 'Formula: Sampling without replacement probabilities', back: 'After removing an item, the total decreases by 1.\n\nExample: bag has 5 red (R), 3 blue (B). Pick 2 without replacement.\n  P(both R) = (5/8) × (4/7) = 20/56 = 5/14\n  P(RB) = (5/8) × (3/7) = 15/56\n  P(BR) = (3/8) × (5/7) = 15/56\n  P(one of each) = 15/56 + 15/56 = 30/56 = 15/28\n\nGCSE Tip: Update the denominator after each selection. Use a tree diagram to avoid errors.', sort_order: 188 },
  { id: 'dc-gcse-formulas-0189', deck_id: 'deck-gcse-formulas', front: 'Formula: Venn diagram probability regions', back: 'For events A and B:\n  P(A only) = P(A) − P(A∩B)\n  P(B only) = P(B) − P(A∩B)\n  P(A∩B) = overlap region\n  P(A∪B) = P(A) + P(B) − P(A∩B)\n  P(neither) = 1 − P(A∪B)\n\nGCSE Tip: Fill in the OVERLAP first when constructing a Venn diagram. Then calculate the "A only" and "B only" regions. Check all values sum correctly to the total.', sort_order: 189 },
  { id: 'dc-gcse-formulas-0190', deck_id: 'deck-gcse-formulas', front: 'Formula: Expected value of a discrete random variable', back: 'E(X) = Σ[x × P(X = x)]\n\nMultiply each outcome by its probability, then sum.\n\nExample: Fair die → E(X) = 1(1/6) + 2(1/6) + 3(1/6) + 4(1/6) + 5(1/6) + 6(1/6) = 21/6 = 3.5\n\nGCSE Tip: Expected value is the theoretical long-run average — it may not be a possible outcome (e.g. 3.5 on a die). Used to determine fairness of a game.', sort_order: 190 },
  { id: 'dc-gcse-formulas-0191', deck_id: 'deck-gcse-formulas', front: 'Formula: P(at least one) — complement method', back: 'P(at least one event occurs) = 1 − P(none occur)\n\nExample: P(machine fails on any day) = 0.1\n  P(fails at least once in 5 days) = 1 − P(never fails)\n  = 1 − (0.9)⁵ = 1 − 0.59049 = 0.41 (to 2 d.p.)\n\nGCSE Tip: This approach is MUCH simpler than enumerating all cases with at least one failure. Always look for "at least one" → use complement.', sort_order: 191 },
  { id: 'dc-gcse-formulas-0192', deck_id: 'deck-gcse-formulas', front: 'Formula: Probability from a frequency tree', back: 'A frequency tree shows COUNTS (not probabilities) at each stage.\n\nTo find a probability: divide the required count by the TOTAL population.\n  P(A and B) = count(A and B) / total\n  P(A|B) = count(A and B) / count(B)\n\nGCSE Tip: Frequency trees use real numbers, making conditional probability calculations more intuitive. Build the tree step by step using given counts.', sort_order: 192 },
  { id: 'dc-gcse-formulas-0193', deck_id: 'deck-gcse-formulas', front: 'Formula: Sample space diagram (two-event grid)', back: 'List all outcomes of one event as rows and the other as columns.\n\nExample: Two dice (6×6 = 36 outcomes).\n  P(sum = 7) = 6/36 = 1/6\n  P(sum > 9) = 6/36 = 1/6\n\nGCSE Tip: A sample space grid makes it easy to count outcomes visually. Always verify total number of outcomes = n(S).', sort_order: 193 },
  { id: 'dc-gcse-formulas-0194', deck_id: 'deck-gcse-formulas', front: 'Formula: Probability with three-set Venn diagrams', back: 'For three events A, B, C:\n  Fill in order: A∩B∩C first, then A∩B only, A∩C only, B∩C only, then A only, B only, C only, then outside.\n\n  P(exactly one of A, B, C) = P(A only) + P(B only) + P(C only)\n  P(A∪B∪C) = P(A)+P(B)+P(C)−P(A∩B)−P(A∩C)−P(B∩C)+P(A∩B∩C)\n\nGCSE Tip: Always work from the INSIDE out when completing a three-set Venn diagram.', sort_order: 194 },
  { id: 'dc-gcse-formulas-0195', deck_id: 'deck-gcse-formulas', front: 'Formula: Listing outcomes systematically', back: 'For combined events, list all outcomes using:\n  • Sample space grid (two events)\n  • Tree diagram (sequential events)\n  • Systematic listing (e.g. AB, AC, BA, BC, CA, CB)\n\nTo count arrangements of n different items: n! = n × (n−1) × … × 2 × 1\n\nGCSE Tip: Systematic listing avoids missing outcomes. Always check the total number of outcomes matches what you expect.', sort_order: 195 },
  { id: 'dc-gcse-formulas-0196', deck_id: 'deck-gcse-formulas', front: 'Formula: Mutually exclusive vs independent — distinction', back: 'Mutually exclusive: P(A ∩ B) = 0 (cannot both occur).\n  → They are NOT independent (unless P(A) = 0 or P(B) = 0).\n\nIndependent: P(A ∩ B) = P(A) × P(B) (knowing one doesn\'t change the other).\n  → They are usually NOT mutually exclusive.\n\nGCSE Tip: Test for independence: does P(A|B) = P(A)? If yes → independent. Test for mutual exclusivity: can both happen at once? If no → mutually exclusive.', sort_order: 196 },
  { id: 'dc-gcse-formulas-0197', deck_id: 'deck-gcse-formulas', front: 'Formula: Probability from two-way tables (conditional)', back: 'From a two-way table with row and column totals:\n\n  P(A) = row total for A / grand total\n  P(A|B) = cell(A and B) / column total for B\n  P(A and B) = cell(A and B) / grand total\n\nGCSE Tip: For conditional probability, the DENOMINATOR changes to the "given" row/column total. Always identify which row or column is the given condition.', sort_order: 197 },
  { id: 'dc-gcse-formulas-0198', deck_id: 'deck-gcse-formulas', front: 'Formula: Theoretical vs experimental probability comparison', back: 'If observed frequency ≈ expected frequency → experiment supports theoretical probability.\nIf observed frequency ≠ expected frequency → possible bias.\n\nMore trials → experimental probability converges to theoretical.\n  This is the Law of Large Numbers.\n\nGCSE Tip: "Comment on whether the coin/dice is fair" → compare observed relative frequency to 0.5 (or 1/6). State that more trials are needed for a reliable conclusion.', sort_order: 198 },
  { id: 'dc-gcse-formulas-0199', deck_id: 'deck-gcse-formulas', front: 'Formula: Conditional probability — medical testing example', back: 'In medical testing, use a frequency tree with a large reference population (e.g. 10 000).\n\nExample: 1% have disease (100 from 10 000). Test: 95% sensitivity, 5% false positive.\n  True positives: 100 × 0.95 = 95\n  False positives: 9900 × 0.05 = 495\n  P(disease | positive) = 95 / (95+495) ≈ 16%\n\nGCSE Tip: This is a classic conditional probability problem. A frequency tree is much clearer than abstract probability fractions for this type of problem.', sort_order: 199 },
  { id: 'dc-gcse-formulas-0200', deck_id: 'deck-gcse-formulas', front: 'Formula: Probability scale and terminology', back: 'Probability scale: 0 (impossible) ← → 1 (certain)\n\nTerms:\n  0 = impossible\n  0.5 = even chance / equally likely\n  1 = certain\n  "Likely" ≈ P > 0.5\n  "Unlikely" ≈ P < 0.5\n  "Very unlikely" ≈ P close to 0\n\nGCSE Tip: In Foundation GCSE, you may be asked to mark probabilities on a number line or to give a probability in words. In Higher, all answers should be numerical.', sort_order: 200 },

  // ── HIGHER — ALGEBRA & NUMBER FORMULAS (cards 201–250) ────────────────────
  { id: 'dc-gcse-formulas-0201', deck_id: 'deck-gcse-formulas', front: 'Formula: Difference of two cubes', back: 'a³ − b³ = (a − b)(a² + ab + b²)\na³ + b³ = (a + b)(a² − ab + b²)\n\nExamples:\n  x³ − 8 = (x−2)(x²+2x+4)\n  27 + y³ = (3+y)(9−3y+y²)\n\nGCSE Tip: Verify by expanding: (a−b)(a²+ab+b²) = a³+a²b+ab² − a²b−ab²−b³ = a³−b³ ✓. Less common at GCSE but expected at Higher level.', sort_order: 201 },
  { id: 'dc-gcse-formulas-0202', deck_id: 'deck-gcse-formulas', front: 'Formula: Polynomial long division', back: 'To divide f(x) by (x − a):\n  Set up: f(x) = (x − a) × Q(x) + R\n  where Q(x) = quotient, R = remainder.\n\nIf f(a) = 0 → (x−a) is a factor (factor theorem) → R = 0.\n\nMethod: "long division" style, or equate coefficients.\n\nGCSE Tip: Use the factor theorem first to confirm (x−a) is a factor, then polynomial long division (or inspection) to find Q(x).', sort_order: 202 },
  { id: 'dc-gcse-formulas-0203', deck_id: 'deck-gcse-formulas', front: 'Formula: Completing the square for vertex and minimum', back: 'y = a(x − h)² + k\n  Vertex: (h, k)\n  Minimum (a>0) or maximum (a<0): y = k, at x = h\n  Axis of symmetry: x = h\n\nTo find h and k:\n  h = −b/(2a)\n  k = f(h) = c − b²/(4a)\n\nGCSE Tip: Completing the square is the definitive method for locating the vertex without calculus.', sort_order: 203 },
  { id: 'dc-gcse-formulas-0204', deck_id: 'deck-gcse-formulas', front: 'Formula: Solving equations by iteration (convergence)', back: 'Rearrange f(x) = 0 to x = g(x).\nIterative formula: xₙ₊₁ = g(xₙ)\n\nConvergence: the iteration converges if |g\'(x)| < 1 near the root.\n\nTo verify convergence at GCSE: show consecutive iterates approach a fixed value.\n\nGCSE Tip: If the sequence diverges (values get further apart), try a different rearrangement. Always show at least 3 iterations and check for convergence.', sort_order: 204 },
  { id: 'dc-gcse-formulas-0205', deck_id: 'deck-gcse-formulas', front: 'Formula: Laws of indices with algebraic expressions', back: 'xᵐ × xⁿ = xᵐ⁺ⁿ\nxᵐ ÷ xⁿ = xᵐ⁻ⁿ\n(xᵐ)ⁿ = xᵐⁿ\n(xy)ⁿ = xⁿyⁿ\n(x/y)ⁿ = xⁿ/yⁿ\nx⁻ⁿ = 1/xⁿ\nx^(m/n) = (ⁿ√x)ᵐ\n\nExample: 8^(2/3) = (∛8)² = 2² = 4\n  (2x)³ = 8x³\n\nGCSE Tip: These apply to algebraic terms as well as numbers. Always look for opportunities to simplify before evaluating.', sort_order: 205 },
  { id: 'dc-gcse-formulas-0206', deck_id: 'deck-gcse-formulas', front: 'Formula: Rationalising a denominator with conjugate', back: 'For 1/(a + b√c):\n  Multiply by (a − b√c)/(a − b√c)\n  Denominator: (a + b√c)(a − b√c) = a² − b²c\n\nFor 1/(a − b√c):\n  Multiply by (a + b√c)/(a + b√c)\n  Denominator: a² − b²c\n\nExample:\n  (2+√3)/(3−√3)\n  Multiply by (3+√3): (6+2√3+3√3+3)/(9−3) = (9+5√3)/6\n\nGCSE Tip: The conjugate of (a+b√c) is (a−b√c). Their product always removes the surd.', sort_order: 206 },
  { id: 'dc-gcse-formulas-0207', deck_id: 'deck-gcse-formulas', front: 'Formula: Solving equations with surds', back: 'Isolate the surd, then square both sides.\n  √(2x+1) = 5 → 2x+1 = 25 → x = 12\n\nFor two surds:\n  √x + √(x+4) = 4\n  √x = 4 − √(x+4)\n  Square: x = 16 − 8√(x+4) + (x+4)\n  8√(x+4) = 20 → √(x+4) = 2.5 → x = 2.25\n\nGCSE Tip: ALWAYS check your solution by substituting back (squaring can introduce extraneous solutions).', sort_order: 207 },
  { id: 'dc-gcse-formulas-0208', deck_id: 'deck-gcse-formulas', front: 'Formula: Expanding triple brackets', back: '(a+b)(c+d)(e+f):\n  Step 1: expand first two brackets → quadratic.\n  Step 2: multiply quadratic by third bracket term by term.\n\nExample: (x+1)(x+2)(x+3)\n  = (x²+3x+2)(x+3)\n  = x³+3x²+3x²+9x+2x+6\n  = x³+6x²+11x+6\n\nGCSE Tip: Take your time on step 2 — four separate multiplications. Show intermediate results clearly.', sort_order: 208 },
  { id: 'dc-gcse-formulas-0209', deck_id: 'deck-gcse-formulas', front: 'Formula: Number of solutions to ax² + bx + c = 0 from discriminant', back: 'b² − 4ac > 0  →  2 distinct real roots (line crosses x-axis twice)\nb² − 4ac = 0  →  1 repeated real root (line touches x-axis)\nb² − 4ac < 0  →  no real roots (parabola entirely above/below x-axis)\n\nGCSE Tip: To prove "no real solutions": show b² − 4ac < 0. To find k for "equal roots": set b² − 4ac = 0 and solve for k.', sort_order: 209 },
  { id: 'dc-gcse-formulas-0210', deck_id: 'deck-gcse-formulas', front: 'Formula: Proof by algebraic manipulation', back: 'Method:\n1. Start with one side (usually the more complex side).\n2. Apply algebraic manipulations (expand, factorise, simplify).\n3. Arrive at the other side.\n4. Conclude with a statement.\n\nDo NOT move terms across the ≡ sign.\n\nExample: Prove n(n+1) is always even.\n  Either n or n+1 is even → their product is even. □\n\nGCSE Tip: "Prove that" is different from "show that" (which may allow working backwards). Both require clear logical steps.', sort_order: 210 },
  { id: 'dc-gcse-formulas-0211', deck_id: 'deck-gcse-formulas', front: 'Formula: Sum of first n squares and cubes', back: 'Sum of first n natural numbers: Σk = n(n+1)/2\nSum of first n squares: Σk² = n(n+1)(2n+1)/6\nSum of first n cubes: Σk³ = [n(n+1)/2]²\n\nGCSE Tip: Sum of 1+2+…+n = n(n+1)/2 is GCSE-required. Sum of squares and cubes appear in A-level but occasionally in GCSE proof questions at Higher tier.', sort_order: 211 },
  { id: 'dc-gcse-formulas-0212', deck_id: 'deck-gcse-formulas', front: 'Formula: Solving two simultaneous quadratic equations', back: 'Substitute one equation into the other to get a single polynomial equation.\n\nExample: x² + y² = 25 and y = 2x\n  x² + 4x² = 25 → 5x² = 25 → x = ±√5\n  y = ±2√5\n  Solutions: (√5, 2√5) and (−√5, −2√5)\n\nGCSE Tip: Substitute the simpler equation into the more complex one. Usually gives 0, 2, or 4 solution pairs.', sort_order: 212 },
  { id: 'dc-gcse-formulas-0213', deck_id: 'deck-gcse-formulas', front: 'Formula: Exponential growth and decay models', back: 'Growth: N(t) = N₀ × (1 + r)^t\nDecay: N(t) = N₀ × (1 − r)^t\n\n  N₀ = initial quantity\n  r = rate of change per time period (decimal)\n  t = number of time periods\n\nHalf-life: N(t) = N₀ × (1/2)^(t/t½)\n\nGCSE Tip: The same formula as compound interest! "Exponential decay" applies to radioactive decay, drug clearance, and depreciation.', sort_order: 213 },
  { id: 'dc-gcse-formulas-0214', deck_id: 'deck-gcse-formulas', front: 'Formula: Finding the equation from a graph of y = kˣ', back: 'y = kˣ passes through (0, 1).\n  At x = 1: y = k (this gives the base).\n  At x = 2: y = k²; etc.\n\nAlternatively: use two points (x₁,y₁) and (x₂,y₂):\n  k = (y₁/y₂)^(1/(x₁−x₂))\n\nGCSE Tip: All exponential graphs y = kˣ pass through (0,1). To find k, use the y-value at x = 1. The base k determines whether the graph is increasing (k>1) or decreasing (0<k<1).', sort_order: 214 },
  { id: 'dc-gcse-formulas-0215', deck_id: 'deck-gcse-formulas', front: 'Formula: Bounds of trigonometric expressions', back: 'sin x ∈ [−1, 1] for all x.\ncos x ∈ [−1, 1] for all x.\ntan x ∈ (−∞, +∞) — unbounded.\n\nGCSE Tip: Used to determine maximum/minimum values of expressions involving sin or cos. E.g. max of 3 + 5 sin x = 3 + 5 = 8; min = 3 − 5 = −2.', sort_order: 215 },
  { id: 'dc-gcse-formulas-0216', deck_id: 'deck-gcse-formulas', front: 'Formula: Proofs involving integers — key forms', back: 'Prove the SQUARE of an odd number is always odd:\n  (2n+1)² = 4n²+4n+1 = 2(2n²+2n)+1 → odd ✓\n\nProve sum of squares of two consecutive integers is always odd:\n  n² + (n+1)² = 2n²+2n+1 = 2(n²+n)+1 → odd ✓\n\nGCSE Tip: Expand, simplify, and show the result is of the required form (2k = even; 2k+1 = odd; 3k = multiple of 3).', sort_order: 216 },
  { id: 'dc-gcse-formulas-0217', deck_id: 'deck-gcse-formulas', front: 'Formula: Direct and inverse proportion — graphs', back: 'y ∝ x:     straight line through origin (y = kx)\ny ∝ x²:    parabola through origin (y = kx²)\ny ∝ √x:    square root curve through origin (y = k√x)\ny ∝ 1/x:   hyperbola, never touching axes (y = k/x)\ny ∝ 1/x²:  steeper hyperbola (y = k/x²)\n\nGCSE Tip: Recognise the shape of each graph. The question may ask you to identify the type of proportion from a graph, or to write the equation given the graph shape and a point.', sort_order: 217 },
  { id: 'dc-gcse-formulas-0218', deck_id: 'deck-gcse-formulas', front: 'Formula: Solving linear + quadratic simultaneous equations', back: '1. From the LINEAR equation, express one variable.\n2. Substitute into the QUADRATIC equation.\n3. Solve the resulting quadratic (by factorising or quadratic formula).\n4. Back-substitute into the linear equation for the other variable.\n5. Give both solution pairs.\n\nGCSE Tip: Always present solutions as pairs: "(x, y) = (2, 3) or (−1, 0)". Substituting into the linear equation (step 4) avoids ± complications from the quadratic.', sort_order: 218 },
  { id: 'dc-gcse-formulas-0219', deck_id: 'deck-gcse-formulas', front: 'Formula: Solving quadratic equations — method selection', back: 'Method hierarchy:\n  1. Factor out common term if possible.\n  2. Factorise (if coefficients are simple).\n  3. Complete the square (for vertex or exact surd solutions).\n  4. Quadratic formula (always works; use when factorising fails).\n\nUse discriminant to decide number of solutions before solving.\n\nGCSE Tip: For calculator exams: quadratic formula is always safe. For non-calculator: factorising is fastest when it works.', sort_order: 219 },
  { id: 'dc-gcse-formulas-0220', deck_id: 'deck-gcse-formulas', front: 'Formula: Error bounds in multi-step calculations', back: 'Maximum result from a/b: use UB(a) / LB(b)\nMinimum result from a/b: use LB(a) / UB(b)\nMaximum from a × b: use UB(a) × UB(b)\nMaximum from a + b: use UB(a) + UB(b)\nMaximum from a − b: use UB(a) − LB(b)\nMinimum from a − b: use LB(a) − UB(b)\n\nGCSE Tip: Think logically: to maximise, choose bounds that make numerator large and denominator small. Always state which bounds you used.', sort_order: 220 },

  // ── HIGHER — GEOMETRY & PROOF (cards 221–270) ─────────────────────────────
  { id: 'dc-gcse-formulas-0221', deck_id: 'deck-gcse-formulas', front: 'Formula: Vector proof — parallel and equal vectors', back: 'Parallel vectors: one is a scalar multiple of the other.\n  a ∥ b  ⟺  a = kb for some scalar k.\n\nEqual vectors: same magnitude and direction (k = 1).\n\nGCSE Tip: In vector proofs, express the path between points as a combination of given vectors a and b. If you get the same expression for two paths, they are equal. Showing one vector = k × another proves parallelism.', sort_order: 221 },
  { id: 'dc-gcse-formulas-0222', deck_id: 'deck-gcse-formulas', front: 'Formula: Midpoint vector', back: 'If M is the midpoint of AB:\n  OM = OA + ½ AB\n  OM = OA + ½(OB − OA)\n  OM = ½(OA + OB)\n  OM = ½(a + b)  where a = OA, b = OB\n\nGCSE Tip: The midpoint formula is the average of the position vectors of A and B. This is used frequently in vector proofs.', sort_order: 222 },
  { id: 'dc-gcse-formulas-0223', deck_id: 'deck-gcse-formulas', front: 'Formula: Circle theorem — angle at centre', back: 'The angle subtended at the CENTRE by an arc is TWICE the angle subtended at the CIRCUMFERENCE by the same arc.\n\n∠AOB = 2∠ACB\n  (O = centre; C = any point on the major arc)\n\nSpecial case: if AOB is a diameter (∠AOB = 180°):\n  ∠ACB = 90° (angle in semicircle)\n\nGCSE Tip: Draw the radius to C and use the isosceles triangle (two radii) to prove this theorem if asked.', sort_order: 223 },
  { id: 'dc-gcse-formulas-0224', deck_id: 'deck-gcse-formulas', front: 'Formula: Circle theorem — angles in the same segment', back: 'Angles subtended by the SAME arc on the SAME side are EQUAL.\n\n∠APB = ∠AQB\n  (both P and Q on the same arc/segment, looking at chord AB)\n\nGCSE Tip: "Angles in the same segment are equal." This appears when there are two angles at the circumference looking at the same chord from the same side.', sort_order: 224 },
  { id: 'dc-gcse-formulas-0225', deck_id: 'deck-gcse-formulas', front: 'Formula: Circle theorem — cyclic quadrilateral', back: 'A cyclic quadrilateral has all four vertices on a circle.\n\nOpposite angles sum to 180° (supplementary):\n  ∠A + ∠C = 180°\n  ∠B + ∠D = 180°\n\nExterior angle of a cyclic quad = opposite interior angle.\n\nGCSE Tip: State the theorem: "Opposite angles in a cyclic quadrilateral sum to 180°."', sort_order: 225 },
  { id: 'dc-gcse-formulas-0226', deck_id: 'deck-gcse-formulas', front: 'Formula: Circle theorem — tangent-radius', back: 'A tangent to a circle is PERPENDICULAR to the radius at the point of tangency.\n\n  OT ⊥ TP  where O = centre, T = point of tangency, P = external point.\n\nConsequence: ∠OTP = 90°, enabling use of Pythagoras:\n  OP² = OT² + TP²\n  Tangent length TP = √(OP² − r²)\n\nGCSE Tip: The 90° angle is ALWAYS at the point where tangent meets circle (not at O or P).', sort_order: 226 },
  { id: 'dc-gcse-formulas-0227', deck_id: 'deck-gcse-formulas', front: 'Formula: Circle theorem — alternate segment theorem', back: 'The angle between a tangent and a chord equals the inscribed angle in the ALTERNATE (opposite) segment.\n\n∠(tangent, chord PT) = ∠(inscribed angle in segment on the other side of PT)\n\nGCSE Tip: Identify: (1) the tangent, (2) the chord, (3) the point where they meet, (4) which is the alternate segment. The equal angles are "on opposite sides" of the chord.', sort_order: 227 },
  { id: 'dc-gcse-formulas-0228', deck_id: 'deck-gcse-formulas', front: 'Formula: Proof of angle in semicircle = 90°', back: 'Given: AB is a diameter; O is the centre; C is any point on the circle.\n\nProof:\n  OA = OB = OC = r (radii)\n  Triangle OAC is isosceles → ∠OAC = ∠OCA = α\n  Triangle OBC is isosceles → ∠OBC = ∠OCB = β\n  In triangle ABC: 2α + 2β = 180° (angle sum)\n  α + β = 90° = ∠ACB ✓\n\nGCSE Tip: This is a classic Higher proof. Use the isosceles triangle property from the two radii.', sort_order: 228 },
  { id: 'dc-gcse-formulas-0229', deck_id: 'deck-gcse-formulas', front: 'Formula: Finding a missing length using similar triangles', back: 'If triangles ABC and PQR are similar (AA, SAS, or SSS):\n  Scale factor k = PQ/AB = QR/BC = PR/AC\n\nFind k from a known pair of corresponding sides, then multiply to find unknown sides.\n\nExample: AB = 6, PQ = 9 → k = 3/2.\n  BC = 4 → QR = 4 × 3/2 = 6.\n\nGCSE Tip: Identify the correct pairs of corresponding sides — matching by equal opposite angles is the most reliable method.', sort_order: 229 },
  { id: 'dc-gcse-formulas-0230', deck_id: 'deck-gcse-formulas', front: 'Formula: Congruence and similarity proof framework', back: 'Proving congruent triangles:\n  State each piece of evidence (side or angle), giving the reason for each.\n  Conclude: "Therefore △ABC ≅ △PQR (SAS/SSS/ASA/AAS/RHS)"\n\nProving similar triangles:\n  Show: two pairs of equal angles (AA is sufficient).\n  Conclude: "Therefore △ABC ∼ △PQR (AA)"\n\nGCSE Tip: For congruence, match vertices in corresponding order. Check your labelling — △ABC ≅ △PQR means A↔P, B↔Q, C↔R.', sort_order: 230 },
  { id: 'dc-gcse-formulas-0231', deck_id: 'deck-gcse-formulas', front: 'Formula: Area of a regular polygon', back: 'For a regular n-gon with side length a:\n  Area = (na²/4) × cot(π/n)\n  or: n × ½r² × sin(360°/n)  (where r = circumradius)\n\nSimpler approach: divide into n congruent isosceles triangles from the centre.\n  Area of each = ½r² sin(360°/n)\n  Total = n × ½r² sin(360°/n)\n\nGCSE Tip: For the common polygons, use: triangle (√3/4 a²), square (a²), hexagon (3√3/2 a²).', sort_order: 231 },
  { id: 'dc-gcse-formulas-0232', deck_id: 'deck-gcse-formulas', front: 'Formula: Applying scale factors to real-world problems', back: 'If a model car has scale factor 1:40:\n  Length: model × 40 = real\n  Area: model × 40² = real (e.g. windscreen area)\n  Volume: model × 40³ = real\n\nGCSE Tip: Always square the scale factor for areas and cube it for volumes. State clearly which scale factor you are using (linear, area, or volume).', sort_order: 232 },
  { id: 'dc-gcse-formulas-0233', deck_id: 'deck-gcse-formulas', front: 'Formula: Angle in a regular polygon using exterior angles', back: 'Sum of all exterior angles of any convex polygon = 360°\nExterior angle of regular n-gon = 360°/n\nInterior angle = 180° − exterior = 180° − 360°/n\n\nTo find n from exterior angle θ: n = 360/θ\nTo find n from interior angle φ: exterior = 180 − φ → n = 360/(180−φ)\n\nGCSE Tip: This is the quickest method for regular polygons. Sum of exterior angles = 360° regardless of the number of sides.', sort_order: 233 },
  { id: 'dc-gcse-formulas-0234', deck_id: 'deck-gcse-formulas', front: 'Formula: Proof involving quadrilaterals (coordinate geometry)', back: 'To prove ABCD is a parallelogram:\n  Show: midpoints of diagonals AC and BD are equal (diagonals bisect each other).\n  OR: show AB ∥ CD (equal gradient) and AB = CD (equal length).\n\nTo prove a square:\n  Prove sides are equal (distance formula) AND adjacent sides are perpendicular (m₁m₂ = −1).\n\nGCSE Tip: Coordinate geometry proofs require clear calculation of gradients, lengths, or midpoints with full working shown.', sort_order: 234 },
  { id: 'dc-gcse-formulas-0235', deck_id: 'deck-gcse-formulas', front: 'Formula: Trig identities — simplification', back: 'tan θ = sin θ / cos θ\nsin²θ + cos²θ = 1\n→ sin²θ = 1 − cos²θ\n→ cos²θ = 1 − sin²θ\n\nApplication:\n  Simplify 1 − cos²x = sin²x\n  Show sin x tan x = sin²x / cos x\n\nGCSE Tip: Substitute the identity to convert between sin² and cos², or to simplify expressions containing tan θ.', sort_order: 235 },
  { id: 'dc-gcse-formulas-0236', deck_id: 'deck-gcse-formulas', front: 'Formula: Sine rule — finding the obtuse angle', back: 'When using sin A = (a sin B)/b, the calculator gives the acute solution A₁.\nThe obtuse solution is A₂ = 180° − A₁.\n\nBoth are valid if A₂ + B < 180° (otherwise the triangle is impossible).\n\nGCSE Tip: Always check whether an obtuse solution is possible. The cosine rule does NOT have this ambiguity — cos A < 0 directly indicates an obtuse angle.', sort_order: 236 },
  { id: 'dc-gcse-formulas-0237', deck_id: 'deck-gcse-formulas', front: 'Formula: Graph sketching — cubics', back: 'y = a(x−p)(x−q)(x−r):\n  Roots at x = p, q, r\n  y-intercept: set x = 0\n  a > 0: bottom-left to top-right\n  a < 0: top-left to bottom-right\n  Repeated root (x−p)²(x−q): touches axis at p, crosses at q\n\nGCSE Tip: Mark all roots and y-intercept. Show correct "shape" (direction of curve for large positive/negative x).', sort_order: 237 },
  { id: 'dc-gcse-formulas-0238', deck_id: 'deck-gcse-formulas', front: 'Formula: Intersecting chords theorem', back: 'If two chords AB and CD intersect at point P inside a circle:\n  PA × PB = PC × PD\n\nIf a tangent PT and secant PAB meet at external point P:\n  PT² = PA × PB\n\nGCSE Tip: This is used for finding lengths in circle problems. Memorise both forms: intersecting chords inside (multiply segments = multiply segments) and tangent-secant from outside (tangent² = external × whole secant).', sort_order: 238 },
  { id: 'dc-gcse-formulas-0239', deck_id: 'deck-gcse-formulas', front: 'Formula: Area under a velocity-time graph', back: 'Area under a v-t graph = distance travelled (displacement)\n\nFor each section:\n  Rectangle: area = base × height = time × velocity\n  Triangle: area = ½ × base × height\n  Trapezium: area = ½(v₁ + v₂) × time\n\nGCSE Tip: Sum the areas of all sections. If the graph goes below the x-axis, that part represents motion in the opposite direction. Count it as negative for displacement, positive for total distance.', sort_order: 239 },
  { id: 'dc-gcse-formulas-0240', deck_id: 'deck-gcse-formulas', front: 'Formula: Gradient of a curve (instantaneous rate of change)', back: 'At a point on a curve: draw a tangent (a straight line just touching the curve).\nGradient = (y₂ − y₁)/(x₂ − x₁) using two points on the tangent.\n\nThis equals the instantaneous rate of change at that point.\n\nGCSE Tip: Choose two points FAR apart on the tangent for greater accuracy. Label the "rise" and "run" clearly on your diagram.', sort_order: 240 },
  { id: 'dc-gcse-formulas-0241', deck_id: 'deck-gcse-formulas', front: 'Formula: Trapezium rule for area under a curve', back: 'Area ≈ h/2 × [y₀ + 2(y₁ + y₂ + … + yₙ₋₁) + yₙ]\n\n  h = width of each strip (equal widths)\n  y₀, y₁, …, yₙ = heights (function values) at each boundary\n\nMore strips → better approximation.\n\nGCSE Tip: The "first and last" values (y₀ and yₙ) are added once; all "middle" values are doubled. Check: are you over- or under-estimating? (Depends on curve concavity.)', sort_order: 241 },
  { id: 'dc-gcse-formulas-0242', deck_id: 'deck-gcse-formulas', front: 'Formula: Proof that √2 is irrational', back: 'Assume √2 = p/q in lowest terms (p, q integers, HCF = 1).\n  2 = p²/q² → p² = 2q² → p² is even → p is even.\n  Let p = 2k → 4k² = 2q² → q² = 2k² → q is even.\n  But p and q are both even — contradicts HCF = 1. ✗\n  Therefore √2 is irrational. □\n\nGCSE Tip: This is a "proof by contradiction". Assume the opposite of what you want to prove, then show this leads to a logical impossibility.', sort_order: 242 },
  { id: 'dc-gcse-formulas-0243', deck_id: 'deck-gcse-formulas', front: 'Formula: Solving trig equations — full solution set', back: 'For sin x = k (0° ≤ x ≤ 360°):\n  x = sin⁻¹(k) and x = 180° − sin⁻¹(k)\n\nFor cos x = k: x = cos⁻¹(k) and x = 360° − cos⁻¹(k)\nFor tan x = k: x = tan⁻¹(k) and x = 180° + tan⁻¹(k)\n\nFor extended ranges (0° ≤ x ≤ 720°): add 360° to all solutions.\nFor sin(2x): period halves → apply to 2x range 0°–720°, then halve.\n\nGCSE Tip: Always check you have found ALL solutions in the given range.', sort_order: 243 },
  { id: 'dc-gcse-formulas-0244', deck_id: 'deck-gcse-formulas', front: 'Formula: Composite solid — surface area calculation', back: 'Total exposed SA = sum of SA of all parts − 2 × (area of each internal interface)\n\nReason: where two parts join, the interface is internal and should NOT be counted (subtract it from both parts).\n\nExample: cone on top of cylinder:\n  Exposed SA = curved SA of cone + πr·l + curved SA of cylinder (2πrh) + bottom circle (πr²)\n  [The joining circle = one πr² is internal — subtract from both cone base and cylinder top]\n\nGCSE Tip: Draw a diagram and label all exposed faces. Be systematic.', sort_order: 244 },
  { id: 'dc-gcse-formulas-0245', deck_id: 'deck-gcse-formulas', front: 'Formula: Finding the equation of a tangent to y = f(x)', back: '1. Find the gradient of the curve at the point (a, f(a)) — use the given function or graphical tangent.\n2. Use point-slope form: y − f(a) = m(x − a)\n3. Rearrange to y = mx + c.\n\nFor a circle: radius gradient = y₁/x₁; tangent gradient = −x₁/y₁.\n\nGCSE Tip: At GCSE without calculus, the gradient is either given, read from a graph, or derived from the circle-tangent relationship.', sort_order: 245 },
  { id: 'dc-gcse-formulas-0246', deck_id: 'deck-gcse-formulas', front: 'Formula: Graphs of y = |f(x)| and y = f(|x|)', back: 'y = |f(x)|: reflect any part of y = f(x) that is BELOW the x-axis to ABOVE it.\n  (y values are always ≥ 0)\n\ny = f(|x|): take the RIGHT half of y = f(x) and reflect it in the y-axis.\n  (x values are symmetric about y-axis)\n\nGCSE Tip: These are Higher-tier modulus graph transformations. The absolute value "flips" negative outputs to positive.', sort_order: 246 },
  { id: 'dc-gcse-formulas-0247', deck_id: 'deck-gcse-formulas', front: 'Formula: Number of sides of a polygon from angle data', back: 'From exterior angle θ: n = 360/θ\nFrom interior angle φ: n = 360/(180−φ)\nFrom angle sum S: n = S/180 + 2\n\nExample: Interior angle = 140° → exterior = 40° → n = 360/40 = 9 sides (nonagon)\n\nGCSE Tip: All answers must give a whole number n ≥ 3. If n is not a whole number, check your working — you may have used the wrong formula.', sort_order: 247 },
  { id: 'dc-gcse-formulas-0248', deck_id: 'deck-gcse-formulas', front: 'Formula: Position vectors and section formula', back: 'If P divides AB in ratio m:n (from A):\n  OP = OA + m/(m+n) × (OB − OA)\n     = (n × OA + m × OB) / (m + n)\n\nMidpoint (m = n = 1):\n  OM = (OA + OB)/2\n\nGCSE Tip: This is the weighted average of two position vectors. For a midpoint, the two position vectors have equal weight (1:1).', sort_order: 248 },
  { id: 'dc-gcse-formulas-0249', deck_id: 'deck-gcse-formulas', front: 'Formula: Summary of graph features to identify', back: 'y = mx + c: straight line, gradient m, y-int c\ny = ax² + bx + c: parabola\ny = x³: S-shaped cubic\ny = 1/x: hyperbola (two branches, asymptotes at axes)\ny = aˣ: exponential (all pass through (0,1))\ny = sin x / y = cos x: waves, period 360°, amplitude 1\ny = tan x: tan graph, period 180°, vertical asymptotes\ny = √x: starts at origin, increases slowly\n\nGCSE Tip: Learn to identify each curve from its equation AND its shape. This is a common "match the graph" question.', sort_order: 249 },
  { id: 'dc-gcse-formulas-0250', deck_id: 'deck-gcse-formulas', front: 'Formula: Invariant points under transformations', back: 'An invariant point maps to itself under a transformation.\n\nReflection: invariant points lie ON the mirror line.\nRotation: only the centre of rotation is invariant.\nEnlargement: only the centre of enlargement is invariant (unless k = 1).\nTranslation: NO invariant points (unless vector = 0).\n\nGCSE Tip: "Find the invariant points" → set up the equation f(x,y) = (x,y) and solve. For a reflection in y = x, points where x = y are invariant.', sort_order: 250 },

  // ── HIGHER — MIXED IMPORTANT FORMULAS (cards 251–300) ──────────────────────
  { id: 'dc-gcse-formulas-0251', deck_id: 'deck-gcse-formulas', front: 'Formula: Completing the square — example walkthrough', back: 'Express 3x² − 12x + 7 in the form a(x + p)² + q.\n\n  3x² − 12x + 7\n  = 3(x² − 4x) + 7\n  = 3[(x − 2)² − 4] + 7\n  = 3(x − 2)² − 12 + 7\n  = 3(x − 2)² − 5\n\nSo: a=3, p=−2, q=−5. Vertex at (2, −5).\n\nGCSE Tip: Always factor out a FIRST when a ≠ 1. The bracket contains the horizontal shift; the constant outside gives the minimum/maximum y-value.', sort_order: 251 },
  { id: 'dc-gcse-formulas-0252', deck_id: 'deck-gcse-formulas', front: 'Formula: Graphs — key points of y = aˣ', back: 'y = aˣ (a > 1, exponential growth):\n  Passes through (0, 1) since a⁰ = 1.\n  At x = 1: y = a.\n  At x = −1: y = 1/a.\n  Asymptote: y = 0 (x-axis) as x → −∞.\n  Always positive (y > 0).\n\nGCSE Tip: To sketch: plot (−1, 1/a), (0, 1), (1, a), (2, a²). Join with a smooth curve rising to the right.', sort_order: 252 },
  { id: 'dc-gcse-formulas-0253', deck_id: 'deck-gcse-formulas', front: 'Formula: Converting between index form and root form', back: 'aⁿ ↔ n-th power\na^(1/n) = ⁿ√a  (1/n power = nth root)\na^(m/n) = (ⁿ√a)ᵐ  (root then power)\na^(−m/n) = 1/(ⁿ√a)ᵐ  (reciprocal)\n\nExamples:\n  64^(1/3) = ∛64 = 4\n  32^(3/5) = (⁵√32)³ = 2³ = 8\n  16^(−3/4) = 1/(⁴√16)³ = 1/8\n\nGCSE Tip: ALWAYS take the root FIRST — gives smaller numbers to work with.', sort_order: 253 },
  { id: 'dc-gcse-formulas-0254', deck_id: 'deck-gcse-formulas', front: 'Formula: Simplifying expressions with multiple index rules', back: 'Apply index laws systematically:\n\nExample: Simplify (4x³)² / (2x)⁻¹\n  = 16x⁶ / (2⁻¹x⁻¹)\n  = 16x⁶ × (1/2)⁻¹ × x\n  = 16x⁶ × 2 × x\n  = 32x⁷\n\nGCSE Tip: Deal with the number part and the variable part separately. Expand brackets with powers first, then apply division/multiplication rules.', sort_order: 254 },
  { id: 'dc-gcse-formulas-0255', deck_id: 'deck-gcse-formulas', front: 'Formula: Finding an equation of a circle given three points', back: 'The general circle equation: x² + y² + cx + dy + e = 0\n\nSubstitute each of the three points to form three simultaneous equations in c, d, e.\nSolve the system.\nComplete the square to find centre and radius.\n\nGCSE Tip: This is a Higher+ topic. Alternatively, the circumcircle can be found by finding the perpendicular bisectors of two chords and their intersection (the circumcentre).', sort_order: 255 },
  { id: 'dc-gcse-formulas-0256', deck_id: 'deck-gcse-formulas', front: 'Formula: Difference of two squares in algebraic fractions', back: '(x² − 9) / (x + 3)  =  (x+3)(x−3) / (x+3)  =  x − 3\n\n(4x² − 1) / (2x + 1)  =  (2x+1)(2x−1) / (2x+1)  =  2x − 1\n\nGCSE Tip: When simplifying algebraic fractions, ALWAYS factorise numerator and denominator first. The difference of two squares is the most common factorisation to spot.', sort_order: 256 },
  { id: 'dc-gcse-formulas-0257', deck_id: 'deck-gcse-formulas', front: 'Formula: Proving a number is rational or irrational', back: 'Rational: can be written as p/q (fraction of integers, q ≠ 0).\nIrrational: cannot.\n\nRational examples: 0.3 = 3/10; 0.̄6 = 2/3; √4 = 2.\nIrrational examples: √2, √3, π, e, √5.\n\nGCSE Tip: "Show that X is rational": express as a fraction. "Show that X is irrational": show it cannot be expressed as a fraction (or that a simpler irrational appears in the expression).', sort_order: 257 },
  { id: 'dc-gcse-formulas-0258', deck_id: 'deck-gcse-formulas', front: 'Formula: Using the cosine rule in 3D problems', back: 'In a 3D problem involving a non-right-angled triangle:\n  1. Identify the triangle (3 sides or 2 sides + included angle).\n  2. Apply the cosine rule.\n\nExample: Tetrahedron with three equal edges. Find the angle between two face diagonals.\n  The three face diagonals form an equilateral triangle — use cosine rule on that triangle.\n\nGCSE Tip: Extract the relevant 2D triangle from the 3D shape and work in that plane.', sort_order: 258 },
  { id: 'dc-gcse-formulas-0259', deck_id: 'deck-gcse-formulas', front: 'Formula: Solving equations involving surds (check for extraneous solutions)', back: 'When you square both sides to remove a surd, you may introduce extraneous solutions.\n\nAlways substitute solutions back into the ORIGINAL equation.\n\nExample: √(x+5) = x − 1\n  Square: x+5 = x²−2x+1 → x²−3x−4=0 → x=4 or x=−1\n  Check x=4: √9 = 3 ✓. Check x=−1: √4 ≠ −2 ✗. Solution: x = 4 only.\n\nGCSE Tip: Extraneous solutions arise because squaring removes information about sign.', sort_order: 259 },
  { id: 'dc-gcse-formulas-0260', deck_id: 'deck-gcse-formulas', front: 'Formula: Percentage change in area/volume with linear change', back: 'If a length increases by p%:\n  New length = original × (1 + p/100)\n  New area = original area × (1 + p/100)²\n  New volume = original volume × (1 + p/100)³\n\nExample: radius of sphere increases by 10%.\n  New volume = original × (1.1)³ = 1.331 × original → 33.1% increase\n\nGCSE Tip: The percentage increase in area or volume is NOT the same as the percentage increase in length.', sort_order: 260 },
  { id: 'dc-gcse-formulas-0261', deck_id: 'deck-gcse-formulas', front: 'Formula: Perpendicular lines from gradients', back: 'm₁ × m₂ = −1  (perpendicular lines)\n  m₂ = −1/m₁\n\nExamples:\n  If m₁ = 2/3, then m₂ = −3/2\n  If m₁ = −5, then m₂ = 1/5\n  If m₁ = 0 (horizontal), m₂ is undefined (vertical)\n\nGCSE Tip: "Negative reciprocal" — flip the fraction and change the sign. This is used for perpendicular bisectors, tangent-radius, and perpendicular height problems.', sort_order: 261 },
  { id: 'dc-gcse-formulas-0262', deck_id: 'deck-gcse-formulas', front: 'Formula: nth term from a table of values', back: 'Step 1: Find differences.\n  If 1st differences constant → linear: Tₙ = dn + c\n  If 2nd differences constant → quadratic: Tₙ = an² + bn + c\n  If ratios constant → geometric: Tₙ = arⁿ⁻¹\n\nStep 2: Determine coefficients by substituting known values.\n\nGCSE Tip: Calculate differences in order. If first differences are NOT constant, check second differences. If second differences are not constant, check ratios.', sort_order: 262 },
  { id: 'dc-gcse-formulas-0263', deck_id: 'deck-gcse-formulas', front: 'Formula: Solving inequalities graphically', back: 'For y > f(x): the required region is ABOVE the curve/line.\nFor y < f(x): the required region is BELOW.\nStrict inequality (<, >): use DASHED boundary.\nNon-strict (≤, ≥): use SOLID boundary.\n\nFor multiple inequalities: shade the region satisfying ALL conditions simultaneously (intersection of regions).\n\nGCSE Tip: Test the point (0,0) in each inequality to confirm which side to shade.', sort_order: 263 },
  { id: 'dc-gcse-formulas-0264', deck_id: 'deck-gcse-formulas', front: 'Formula: Proof that consecutive odd numbers sum to a multiple of 4', back: 'Let the two consecutive odd numbers be (2n−1) and (2n+1).\n\nSum = (2n−1) + (2n+1) = 4n\n\nThis is a multiple of 4. □\n\nGCSE Tip: Consecutive odd numbers differ by 2. Label them 2n−1 and 2n+1 (symmetric around 2n). This is cleaner than using 2n+1 and 2n+3.', sort_order: 264 },
  { id: 'dc-gcse-formulas-0265', deck_id: 'deck-gcse-formulas', front: 'Formula: Solving equations with composite functions', back: 'Solve f(g(x)) = k:\n  Step 1: Let g(x) = t → solve f(t) = k for t.\n  Step 2: Solve g(x) = t for x.\n\nExample: f(x) = 2x+1, g(x) = x². Solve fg(x) = 9.\n  f(g(x)) = 2x²+1 = 9 → 2x² = 8 → x² = 4 → x = ±2.\n\nGCSE Tip: Alternatively, just substitute g(x) directly into f and solve. Always check by substituting back.', sort_order: 265 },
  { id: 'dc-gcse-formulas-0266', deck_id: 'deck-gcse-formulas', front: 'Formula: Standard deviation interpretation', back: 'Standard deviation (σ or s): the average distance of data points from the mean.\n\n  Low SD → data closely clustered around the mean.\n  High SD → data widely spread.\n\nFor comparing two datasets:\n  Higher mean → typically better performance.\n  Lower SD → more consistent/reliable.\n\nGCSE Tip: GCSE exams compare SDs without requiring calculation. "Group A has a lower standard deviation, suggesting their performance was more consistent."', sort_order: 266 },
  { id: 'dc-gcse-formulas-0267', deck_id: 'deck-gcse-formulas', front: 'Formula: Angle between two vectors', back: 'cos θ = (a · b) / (|a| |b|)\n\nDot product: a · b = a₁b₁ + a₂b₂ (for 2D)\n  or a₁b₁ + a₂b₂ + a₃b₃ (for 3D)\n\nExample: a = (3/4), b = (0/5)\n  a·b = 0+20 = 20; |a|=5, |b|=5\n  cos θ = 20/25 = 4/5 → θ = cos⁻¹(0.8) ≈ 36.9°\n\nGCSE Tip: This is an A-level concept but sometimes appears in GCSE Higher proof contexts. Perpendicular vectors have a·b = 0.', sort_order: 267 },
  { id: 'dc-gcse-formulas-0268', deck_id: 'deck-gcse-formulas', front: 'Formula: Solving trigonometric equations with compound arguments', back: 'Example: Solve sin(2x) = 0.5 for 0° ≤ x ≤ 180°\n\n  Let u = 2x → 0° ≤ u ≤ 360°\n  sin u = 0.5 → u = 30° or u = 150°\n  → x = 15° or x = 75°\n\nExample: Solve tan(x + 30°) = 1 for 0° ≤ x ≤ 360°\n  u = x + 30° → 30° ≤ u ≤ 390°\n  tan u = 1 → u = 45° or u = 225°\n  → x = 15° or x = 195°\n\nGCSE Tip: Adjust the range for u (the compound argument) before finding solutions.', sort_order: 268 },
  { id: 'dc-gcse-formulas-0269', deck_id: 'deck-gcse-formulas', front: 'Formula: Proof — sum of exterior angles of any polygon', back: 'Proof: Imagine walking around the perimeter of any convex polygon.\n  At each vertex, you turn through the exterior angle.\n  After completing the circuit, you have turned a full 360°.\n  Therefore: sum of all exterior angles = 360°.\n\nThis is true for ANY convex polygon, regardless of the number of sides.\n\nGCSE Tip: This is a beautiful intuitive proof. Use it to justify why sum of exterior angles = 360° in formal responses.', sort_order: 269 },
  { id: 'dc-gcse-formulas-0270', deck_id: 'deck-gcse-formulas', front: 'Formula: Manipulating surds — (a+√b)(a−√b)', back: '(a + √b)(a − √b) = a² − b\n\nThis is the difference of two squares, producing a rational result.\n\nExamples:\n  (3 + √5)(3 − √5) = 9 − 5 = 4\n  (2 + √7)(2 − √7) = 4 − 7 = −3\n  (√3 + √2)(√3 − √2) = 3 − 2 = 1\n\nGCSE Tip: This product is always used in rationalising denominators. Memorise the pattern — it removes ALL surds from the result.', sort_order: 270 },

  // ── HIGHER — FINAL 30 FORMULAS (cards 271–300) ────────────────────────────
  { id: 'dc-gcse-formulas-0271', deck_id: 'deck-gcse-formulas', front: 'Formula: Completing the square — use in solving', back: 'To solve x² + bx + c = 0 by completing the square:\n  (x + b/2)² = (b/2)² − c\n  x = −b/2 ± √((b/2)² − c)\n\nExample: x² + 6x + 4 = 0\n  (x+3)² − 9 + 4 = 0\n  (x+3)² = 5\n  x = −3 ± √5\n\nGCSE Tip: This gives exact (surd) solutions. It is also the method used to derive the quadratic formula.', sort_order: 271 },
  { id: 'dc-gcse-formulas-0272', deck_id: 'deck-gcse-formulas', front: 'Formula: Geometric sequence sum (finite)', back: 'Sₙ = a(1 − rⁿ)/(1 − r)  for r ≠ 1\n  or: Sₙ = a(rⁿ − 1)/(r − 1)  (alternative form)\n\n  a = first term, r = common ratio, n = number of terms\n\nExample: 3 + 6 + 12 + 24 + 48 (a=3, r=2, n=5):\n  S₅ = 3(2⁵ − 1)/(2−1) = 3(31) = 93\n\nGCSE Tip: For |r| < 1 and n → ∞: S∞ = a/(1−r) (infinite sum, A-level).', sort_order: 272 },
  { id: 'dc-gcse-formulas-0273', deck_id: 'deck-gcse-formulas', front: 'Formula: Surds — multiplying binomials', back: '(a + b√c)(d + e√c) = ad + ae√c + bd√c + be·c\n  = (ad + bec) + (ae + bd)√c\n\nExample:\n  (2 + 3√5)(4 − √5)\n  = 8 − 2√5 + 12√5 − 3(5)\n  = 8 − 15 + (−2+12)√5\n  = −7 + 10√5\n\nGCSE Tip: Expand as a normal FOIL, remembering √5 × √5 = 5 (not √25). Collect rational and irrational parts separately.', sort_order: 273 },
  { id: 'dc-gcse-formulas-0274', deck_id: 'deck-gcse-formulas', front: 'Formula: Proof — no perfect square is 2 more than a multiple of 4', back: 'Any integer n is either even (n=2k) or odd (n=2k+1).\n\nEven: n² = 4k² → multiple of 4 (remainder 0)\nOdd: n² = (2k+1)² = 4k²+4k+1 = 4(k²+k)+1 → remainder 1 when divided by 4\n\nSo n² always has remainder 0 or 1 when divided by 4.\nTherefore n² can never be 2 more than a multiple of 4. □\n\nGCSE Tip: Proof by exhaustion — check all possible cases (even and odd).', sort_order: 274 },
  { id: 'dc-gcse-formulas-0275', deck_id: 'deck-gcse-formulas', front: 'Formula: Finding the HCF and LCM from a Venn diagram', back: 'For numbers A and B:\n  1. Write prime factor decomposition of each.\n  2. Draw two overlapping circles.\n  3. Place shared prime factors in the OVERLAP.\n  4. Place remaining factors in the appropriate circle.\n  5. HCF = product of factors in the overlap.\n  6. LCM = product of ALL factors in both circles.\n\nGCSE Tip: Always write prime factors as powers (e.g. 2³, not 2×2×2) for clarity.', sort_order: 275 },
  { id: 'dc-gcse-formulas-0276', deck_id: 'deck-gcse-formulas', front: 'Formula: Sector angle from arc length or area', back: 'From arc length L:\n  θ = (L / (2πr)) × 360° = 360°L / (2πr)\n\nFrom sector area A:\n  θ = (A / πr²) × 360°\n\nGCSE Tip: Rearrange the arc/sector formulas when given the arc or area and asked for the angle. Always check units and whether the answer is in degrees.', sort_order: 276 },
  { id: 'dc-gcse-formulas-0277', deck_id: 'deck-gcse-formulas', front: 'Formula: Equation of a perpendicular bisector', back: 'Perpendicular bisector of AB:\n  Passes through midpoint M of AB.\n  Has gradient m⊥ = −1/m_AB.\n  Equation: y − M_y = m⊥(x − M_x)\n\nThis line is the locus of points equidistant from A and B.\n\nGCSE Tip: Two steps: (1) find midpoint, (2) find perpendicular gradient. Then use point-slope form. Used in coordinate geometry and circle theorem problems.', sort_order: 277 },
  { id: 'dc-gcse-formulas-0278', deck_id: 'deck-gcse-formulas', front: 'Formula: Angle bisector of two lines', back: 'The angle bisector of two lines divides the angle between them equally.\n\nFor two lines meeting at a point, the angle bisector passes through the vertex at angle θ/2 where θ is the angle between the lines.\n\nGCSE Tip: In locus problems, the angle bisector is the locus of points equidistant from both lines. For construction, use a compass to find the bisector (equal arcs on both arms).', sort_order: 278 },
  { id: 'dc-gcse-formulas-0279', deck_id: 'deck-gcse-formulas', front: 'Formula: Standard form arithmetic — addition and subtraction', back: 'To add/subtract in standard form:\n  1. Convert to the same power of 10.\n  2. Add/subtract the A values.\n  3. Adjust if necessary.\n\nExample: 3.4 × 10⁵ + 4.6 × 10⁴\n  = 3.4 × 10⁵ + 0.46 × 10⁵\n  = 3.86 × 10⁵\n\nGCSE Tip: For multiplication/division, you can keep different powers (just add/subtract indices). For addition/subtraction, you MUST use the same power first.', sort_order: 279 },
  { id: 'dc-gcse-formulas-0280', deck_id: 'deck-gcse-formulas', front: 'Formula: Gradient between two points and the angle it makes', back: 'm = (y₂ − y₁)/(x₂ − x₁)\nAngle with positive x-axis: θ = tan⁻¹(m)\n\nGCSE Tip: A gradient of 1 makes 45°; gradient of √3 makes 60°; gradient of 1/√3 makes 30°. For negative gradients, the angle is between 90° and 180°.', sort_order: 280 },
  { id: 'dc-gcse-formulas-0281', deck_id: 'deck-gcse-formulas', front: 'Formula: The nth term of a sequence involving fractions', back: 'Identify the numerator and denominator patterns separately.\n\nExample: 2/3, 4/5, 6/7, 8/9, …\n  Numerator: 2, 4, 6, 8, … → 2n\n  Denominator: 3, 5, 7, 9, … → 2n + 1\n  nth term = 2n/(2n+1)\n\nGCSE Tip: Split fractions into two sequences. Find the nth term of each, then combine.', sort_order: 281 },
  { id: 'dc-gcse-formulas-0282', deck_id: 'deck-gcse-formulas', front: 'Formula: Proof — sum of angles in a triangle = 180°', back: 'Draw line through A parallel to BC.\n  Let ∠ABC = β and ∠ACB = γ.\n  Alternate angles: ∠DAB = β (DA ∥ BC) and ∠EAC = γ (AE ∥ BC)\n  ∠DAB + ∠BAC + ∠EAC = 180° (angles on straight line)\n  β + ∠BAC + γ = 180°\n  Therefore angles in triangle sum to 180°. □\n\nGCSE Tip: This is a classic Higher proof. The key step is drawing the parallel line through the apex.', sort_order: 282 },
  { id: 'dc-gcse-formulas-0283', deck_id: 'deck-gcse-formulas', front: 'Formula: Finding the radius from a sector area or arc length', back: 'From sector area A = (θ/360)πr²:\n  r = √(360A / (πθ))\n\nFrom arc length L = (θ/360) × 2πr:\n  r = 360L / (2πθ) = 180L / (πθ)\n\nGCSE Tip: Rearrange the standard formula for r. This appears when area or arc is given and radius is unknown. Keep exact values until the last step.', sort_order: 283 },
  { id: 'dc-gcse-formulas-0284', deck_id: 'deck-gcse-formulas', front: 'Formula: Key properties of the sine and cosine curves', back: 'Both y = sin x and y = cos x have:\n  Period: 360° (or 2π radians)\n  Amplitude: 1\n  Range: −1 ≤ y ≤ 1\n\nRelationship: cos x = sin(x + 90°)\n  → cosine curve is the sine curve shifted 90° to the LEFT\n\nGCSE Tip: To sketch y = sin x + 2 (shift up 2): the range becomes 1 ≤ y ≤ 3. The period and amplitude remain unchanged.', sort_order: 284 },
  { id: 'dc-gcse-formulas-0285', deck_id: 'deck-gcse-formulas', front: 'Formula: Proof — the angle at the circumference is half the angle at the centre', back: 'Given: O is centre; P is a point on the major arc; A, B are on the circle.\nLet ∠APB = α. To show ∠AOB = 2α.\n\nJoin OP. OA = OP = OB (radii).\n△OAP isosceles → ∠OAP = ∠OPA = α₁\n∠AOQ = 2α₁ (exterior angle of triangle)\nSimilarly ∠BOQ = 2α₂\n∠AOB = 2α₁ + 2α₂ = 2(α₁ + α₂) = 2∠APB ✓\n\nGCSE Tip: This is a required Higher proof. Join the centre to the circumference point P.', sort_order: 285 },
  { id: 'dc-gcse-formulas-0286', deck_id: 'deck-gcse-formulas', front: 'Formula: Histogram — reading off number of values', back: 'From a histogram:\n  Frequency = frequency density × class width\n  = height of bar × width of bar\n  = area of bar\n\nTo estimate proportion of values in a sub-interval:\n  Find fraction of the bar: (proportion of width) × frequency density × class width\n\nGCSE Tip: ALWAYS multiply height by width to get frequency. Never read height as frequency when class widths differ.', sort_order: 286 },
  { id: 'dc-gcse-formulas-0287', deck_id: 'deck-gcse-formulas', front: 'Formula: Percentiles and their relationship to quartiles', back: 'Percentile: the value below which a given percentage of data falls.\n  25th percentile = Q1 (lower quartile)\n  50th percentile = median (Q2)\n  75th percentile = Q3 (upper quartile)\n  90th percentile: 90% of data lies below this value\n\nFrom cumulative frequency curve:\n  p-th percentile at cumulative freq = (p/100) × n\n\nGCSE Tip: Higher GCSE may ask for percentiles. Use the cumulative frequency curve and read off at the appropriate cumulative frequency value.', sort_order: 287 },
  { id: 'dc-gcse-formulas-0288', deck_id: 'deck-gcse-formulas', front: 'Formula: Finding the area of a triangle in a coordinate plane', back: 'Method 1 (shoe-lace / coordinate formula for triangle with vertices (x₁,y₁), (x₂,y₂), (x₃,y₃)):\n  Area = ½|x₁(y₂−y₃) + x₂(y₃−y₁) + x₃(y₁−y₂)|\n\nMethod 2: find base and perpendicular height, then A = ½bh.\n\nExample: (0,0), (6,0), (3,4)\n  Area = ½|0(0−4)+6(4−0)+3(0−0)| = ½|24| = 12\n\nGCSE Tip: The shoelace formula is fast and exact. Method 2 may require the distance formula to find the height.', sort_order: 288 },
  { id: 'dc-gcse-formulas-0289', deck_id: 'deck-gcse-formulas', front: 'Formula: Trig — solving sin(ax + b) = k', back: 'Step 1: Let u = ax + b. Determine range of u from range of x.\nStep 2: Solve sin u = k in the u-range using CAST diagram.\nStep 3: Convert back to x: x = (u − b)/a.\n\nExample: Solve sin(2x + 30°) = 0.5, 0° ≤ x ≤ 180°\n  u = 2x+30°; 30° ≤ u ≤ 390°\n  sin u = 0.5 → u = 30°, 150° (in 0°–360°); add 360°: u = 390° (outside)\n  → 2x+30 = 30 → x=0; 2x+30=150 → x=60°\n\nGCSE Tip: Adjust the u-range first before finding solutions.', sort_order: 289 },
  { id: 'dc-gcse-formulas-0290', deck_id: 'deck-gcse-formulas', front: 'Formula: Converting units of speed', back: 'm/s → km/h: multiply by 3.6 (× 3600 ÷ 1000)\nkm/h → m/s: divide by 3.6 (× 1000 ÷ 3600)\n\nm/s → miles/h: multiply by 2.237 (approximately)\n\nExample: 20 m/s = 20 × 3.6 = 72 km/h\n\nGCSE Tip: 1 m/s = 3.6 km/h. For non-SI units, use the given conversion rate. Always show the conversion factor clearly.', sort_order: 290 },
  { id: 'dc-gcse-formulas-0291', deck_id: 'deck-gcse-formulas', front: 'Formula: Solving fractional index equations', back: 'Solve xᵐ/ⁿ = k:\n  Raise both sides to the power n/m: x = k^(n/m)\n\nExample: x^(3/4) = 8\n  x = 8^(4/3) = (∛8)⁴ = 2⁴ = 16\n\nExample: x^(−1/2) = 3\n  x = 3^(−2) = 1/9\n\nGCSE Tip: Apply the inverse index (reciprocal of the power) to both sides. The inverse of a^(m/n) is a^(n/m).', sort_order: 291 },
  { id: 'dc-gcse-formulas-0292', deck_id: 'deck-gcse-formulas', front: 'Formula: Area of a segment — worked example', back: 'Sector OAB: r = 10 cm, θ = 80°.\n  Sector area = (80/360)π(100) = 200π/9 cm²\n  Triangle OAB area = ½(10)(10)sin80° = 50 sin80°\n  Segment area = 200π/9 − 50 sin80°\n  ≈ 69.81 − 49.24 ≈ 20.57 cm²\n\nGCSE Tip: Segment = sector − triangle. The triangle uses the formula ½ab sin C with both sides = radius and angle = sector angle.', sort_order: 292 },
  { id: 'dc-gcse-formulas-0293', deck_id: 'deck-gcse-formulas', front: 'Formula: Volume of a frustum — worked example', back: 'Full cone: height H = 12, radius R = 6. Small cone removed: height h = 4, radius r = 2. (Scale factor k = 1/3)\n  V(full) = ⅓π(36)(12) = 144π\n  V(small) = ⅓π(4)(4) = 16π/3\n  Frustum = 144π − 16π/3 = (432π − 16π)/3 = 416π/3 ≈ 435.6 cm³\n\nGCSE Tip: Use similar triangles to find the small cone dimensions. Scale factor k applies to radius AND height.', sort_order: 293 },
  { id: 'dc-gcse-formulas-0294', deck_id: 'deck-gcse-formulas', front: 'Formula: Proof — a triangle has exactly 180° (exterior angle)', back: 'Exterior angle theorem: the exterior angle of a triangle equals the sum of the two non-adjacent interior angles.\n\n∠ACD = ∠A + ∠B (where ∠ACD is the exterior angle at C)\n\nProof:\n  ∠A + ∠B + ∠BCA = 180° (angle sum)\n  ∠BCA + ∠ACD = 180° (angles on straight line)\n  ∴ ∠ACD = ∠A + ∠B ✓\n\nGCSE Tip: State the reason: "exterior angle of a triangle equals sum of the two non-adjacent interior angles."', sort_order: 294 },
  { id: 'dc-gcse-formulas-0295', deck_id: 'deck-gcse-formulas', front: 'Formula: Applying bounds to the calculation of density', back: 'Given mass m = 4.5 kg (±0.05) and volume V = 0.9 m³ (±0.05).\n\nMax density = UB(m) / LB(V) = 4.55 / 0.85 ≈ 5.353 kg/m³\nMin density = LB(m) / UB(V) = 4.45 / 0.95 ≈ 4.684 kg/m³\n\nGCSE Tip: To maximise a ratio, use the largest numerator and smallest denominator. To minimise, use smallest numerator and largest denominator.', sort_order: 295 },
  { id: 'dc-gcse-formulas-0296', deck_id: 'deck-gcse-formulas', front: 'Formula: Sine rule proof sketch', back: 'In △ABC, draw altitude h from A to BC.\n  h = b sin C = c sin B\n  → b/sin B = c/sin C\n\nDraw altitude from B:\n  h\' = a sin C = c sin A\n  → a/sin A = c/sin C\n\nCombining: a/sin A = b/sin B = c/sin C ✓\n\nGCSE Tip: This proof uses the area formula: Area = ½bh = ½bc sin A. Express two areas differently to get the sine rule.', sort_order: 296 },
  { id: 'dc-gcse-formulas-0297', deck_id: 'deck-gcse-formulas', front: 'Formula: Proportion problems — harder types (y ∝ x^(1/3))', back: 'y ∝ x^(1/3) means y = k × x^(1/3) = k × ∛x\n\nExample: y = 4 when x = 8.\n  4 = k × ∛8 = 2k → k = 2\n  y = 2∛x\n  When x = 27: y = 2 × 3 = 6\n\nGCSE Tip: "Proportional to the cube root" is a Higher-only type. Find k from the given pair, then use the formula to find other values.', sort_order: 297 },
  { id: 'dc-gcse-formulas-0298', deck_id: 'deck-gcse-formulas', front: 'Formula: Proof — if n is odd, then n³ is odd', back: 'Let n = 2k + 1 (any odd integer).\n  n³ = (2k+1)³\n  = 8k³ + 12k² + 6k + 1\n  = 2(4k³ + 6k² + 3k) + 1\n  = 2m + 1 (where m = 4k³+6k²+3k is an integer)\n  Therefore n³ is odd. □\n\nGCSE Tip: Expanding (2k+1)³ using the binomial expansion: (2k+1)³ = (2k)³ + 3(2k)²(1) + 3(2k)(1)² + 1³.', sort_order: 298 },
  { id: 'dc-gcse-formulas-0299', deck_id: 'deck-gcse-formulas', front: 'Formula: Simplifying complex algebraic fractions', back: 'Method: factorise fully, then cancel common factors.\n\nExample:\n  (x² − 4) / (x² + 3x + 2) × (x + 1)/(x − 2)\n  = [(x+2)(x−2)] / [(x+2)(x+1)] × (x+1)/(x−2)\n  = [(x+2)(x−2)(x+1)] / [(x+2)(x+1)(x−2)]\n  = 1\n\nGCSE Tip: For compound fractions (fractions within fractions), multiply by the reciprocal or clear all denominators by multiplying top and bottom by the LCM.', sort_order: 299 },
  { id: 'dc-gcse-formulas-0300', deck_id: 'deck-gcse-formulas', front: 'Formula: Which formula to use — decision guide', back: 'Area: triangle (½bh or ½ab sinC), trapezium (½(a+b)h), circle (πr²), sector ((θ/360)πr²)\nVolume: prism (A×l), cone (⅓πr²h), sphere (4/3 πr³)\nTrig: right triangle (SOH CAH TOA), any triangle (sine/cosine rule)\nSequences: linear (dn+c), quadratic (an²+bn+c), geometric (arⁿ⁻¹)\nProbability: P(A or B) = P(A)+P(B)−P(A∩B), P(A and B) = P(A)×P(B|A)\n\nGCSE Tip: Building this mental decision tree is the key skill in GCSE Maths — knowing WHEN to apply each formula matters as much as knowing the formula itself.', sort_order: 300 },
];
